			e.pos = V.vclone(this.pos)
			this.phase = "princess_saved"

			queue_insert(store, e)

			return
		end

		if this.unit.is_stunned then
			U.animation_start(this, "idle", nil, store.tick_ts, true)
		else
			action = ready_for_action()

