			local aa = a.list[idx]

			if idx == 1 then
				glow_tween.keys = glow_tween.keys_lightning
				glow_tween.ts = store.tick_ts
				glow.hidden = false

				S:queue(aa.sound)
				U.animation_start(this, aa.animation, nil, store.tick_ts, true)

