scripts.endless_mage_thunder = {}

function scripts.endless_mage_thunder.update(this, store)
	local function create_thunder(thunder, pos)
		local e = E:create_entity("fx_power_thunder_" .. math.random(1, 2))

		e.pos.x, e.pos.y = pos.x, pos.y
		e.render.sprites[1].flip_x = math.random() < 0.5
		e.render.sprites[1].ts = store.tick_ts
		e.render.sprites[1].scale = v(0.8, 0.8)

		if REF_H - pos.y > e.image_h then
			e.render.sprites[1].scale = v(0.8, (REF_H - pos.y) / e.image_h)
		end

		queue_insert(store, e)

		e = E:create_entity("fx_power_thunder_explosion")
		e.pos.x, e.pos.y = pos.x, pos.y
		e.render.sprites[1].ts = store.tick_ts
		e.render.sprites[1].scale = v(0.8, 0.8)
		e.render.sprites[2].ts = store.tick_ts
		e.render.sprites[2].scale = v(0.8, 0.8)

		queue_insert(store, e)

		e = E:create_entity("fx_power_thunder_explosion_decal")
		e.pos.x, e.pos.y = pos.x, pos.y
		e.render.sprites[1].ts = store.tick_ts
		e.render.sprites[1].scale = v(0.8, 0.8)

		queue_insert(store, e)

		if thunder.pop and math.random() < thunder.pop_chance then
			local e = SU.create_pop(store, this.pos, thunder.pop)

			queue_insert(store, e)
		end

		local targets = U.find_enemies_in_range(store, pos, 0, thunder.damage_radius, this.vis_flags, this.vis_bans)

		if targets then
			for _, target in pairs(targets) do
				local d = E:create_entity("damage")

				d.damage_type = thunder.damage_type
				d.value = math.random(thunder.damage_min, thunder.damage_max)
				d.target_id = target.id
				d.source_id = this.id

				SU.magic_armor_dec(target, 0.01)
				queue_damage(store, d)
			end
		end
	-- AC:inc_check("LIGHTNING_CAST")
	end

	local visited = {}
	local t1, t2 = this.thunders[1], this.thunders[2]

	t1.created, t2.created = 0, 0

	if t2.count > 0 then
		t2.cooldown = U.frandom(t2.delay_min, t2.delay_max)
		t2.ts = store.tick_ts
	end

	while t1.created < t1.count or t2.created < t2.count do
		for _, thunder in pairs(this.thunders) do
			if thunder.created < thunder.count and store.tick_ts - thunder.ts > thunder.cooldown then
				local pos

				if thunder.targeting == "nearest" then
					if thunder.created == 0 then
						pos = this.pos
					else
						local target = U.find_nearest_enemy(store, this.pos, 0, thunder.range, this.vis_flags, this.vis_bans, function(v)
							return not table.contains(visited, v)
						end)

						if target then
							table.insert(visited, target)

							pos = target.pos
						else
							local nearest = P:nearest_nodes(this.pos.x, this.pos.y, nil, nil, true)

							if #nearest > 0 then
								local pi, spi, ni = unpack(nearest[1])
								local no = math.random(-this.nodes_spread, this.nodes_spread)

								if not P:is_node_valid(pi, ni + no) then
									no = 0
								end

								pos = P:node_pos(pi, math.random(1, 3), ni + no)
							end
						end
					end
				else
					local target = U.find_random_enemy(store, this.pos, 0, thunder.range, this.vis_flags, this.vis_bans)

					if target then
						pos = target.pos
					else
						pos = P:get_random_position(10, bor(TERRAIN_LAND, TERRAIN_WATER)) or this.pos
					end
				end

				if pos then
					create_thunder(thunder, pos)
				end

				thunder.ts = store.tick_ts
				thunder.cooldown = U.frandom(thunder.delay_min, thunder.delay_max)
				thunder.created = thunder.created + 1
			end
		end

		coroutine.yield()
	end

	queue_remove(store, this)
end

scripts.moon_controller_s91 = {}

function scripts.moon_controller_s91.update(this, store)
	local glow_sid, eyes_sid = 1, 4
	local glow_s = this.render.sprites[glow_sid]
	local eyes_s = this.render.sprites[eyes_sid]
	local moon = this.decal_moon_dark
	local moon_s = moon.render.sprites[1]
	local moon_light = this.decal_moon_light
	local overlay = this.moon_overlay
	local fade_time = overlay.tween.props[1].keys[2][1]
	local transit_time = this.transit_time
	local hold_time = this.hold_time
	local inactive_time = this.inactive_time

	while not store.enemy_count or store.enemy_count == 0 do
		coroutine.yield()
	end

	local time = store.tick_ts

	while true do
		while store.tick_ts - time < inactive_time do
			coroutine.yield()
		end

		moon.tween.props[1].keys = {{0, math.pi / 5}, {transit_time, math.pi * 0.5}}
		moon.tween.disabled = nil
		moon.tween.ts = store.tick_ts
		time = store.tick_ts

		while store.tick_ts - time < transit_time do
			coroutine.yield()
		end

		moon.tween.props[1].keys = {{0, math.pi / 5}, {transit_time, math.pi * 0.5}}
		moon.tween.disabled = nil
		moon.tween.ts = store.tick_ts
		moon_light.tween.ts = store.tick_ts
		moon_light.tween.reverse = false
		this.tween.ts = store.tick_ts
		this.tween.reverse = false
		overlay.tween.ts = store.tick_ts
		overlay.tween.reverse = false

		S:queue("MusicHalloweenMoon")
		signal.emit("moon-changed", true, store)

		time = store.tick_ts
		this.moon_active = true

		local spawn_count = store.wave_group_number and math.ceil(store.wave_group_number / 2) or 1
		local spawn_gap = hold_time / spawn_count

		for _, e in pairs(store.enemies) do
			e.unit.damage_factor = e.unit.damage_factor * this.enemy_damage_factor

			U.speed_mul(e, this.enemy_speed_factor)
			SU.insert_unit_cooldown_buff(store.tick_ts, e, this.enemy_cooldown_factor)

			e.health.damage_factor = e.health.damage_factor * this.enemy_health_factor
		end

		U.insert_insert_hook(store, this.id, function(e, d)
			if e.enemy then
				e.unit.damage_factor = e.unit.damage_factor * this.enemy_damage_factor

				U.speed_mul(e, this.enemy_speed_factor)
				SU.insert_unit_cooldown_buff(store.tick_ts, e, this.enemy_cooldown_factor)

				e.health.damage_factor = e.health.damage_factor * this.enemy_health_factor
			end
		end)

		local spawn_ts = time - spawn_gap

		while store.tick_ts - time < hold_time do
			if store.tick_ts - spawn_ts > spawn_gap then
				local e = E:create_entity(this.spawn_creep)

				e.nav_path.pi = math.random(2, 4)
				e.nav_path.spi = 1
				e.nav_path.ni = P:get_start_node(e.nav_path.pi)

				queue_insert(store, e)

				spawn_ts = store.tick_ts
			end

			coroutine.yield()
		end

		for _, e in pairs(store.enemies) do
			e.unit.damage_factor = e.unit.damage_factor / this.enemy_damage_factor

			U.speed_div(e, this.enemy_speed_factor)
			SU.remove_unit_cooldown_buff(store.tick_ts, e, this.enemy_cooldown_factor)

			e.health.damage_factor = e.health.damage_factor / this.enemy_health_factor
		end

		U.remove_insert_hook(store, this.id)
		signal.emit("moon-changed", false, store)

		this.moon_active = false

		if not this.tween.reverse then
			this.tween.ts = store.tick_ts
			this.tween.reverse = true
		end

		if not overlay.tween.reverse then
			overlay.tween.ts = store.tick_ts
			overlay.tween.reverse = true
		end

		if not moon_light.tween.reverse then
			moon_light.tween.ts = store.tick_ts
			moon_light.tween.reverse = true

			U.y_wait(store, fade_time)
		end

		S:queue(string.format("MusicBattle_%02d", store.level_idx), {
			seek = 19.774
		})

		moon.tween.props[1].keys = {{0, moon_s.r}, {transit_time, 4 * math.pi / 5}}
		moon.tween.ts = store.tick_ts
		time = store.tick_ts

		while store.tick_ts - time < transit_time do
			coroutine.yield()
		end
	end
end

scripts.decal_soldier_shadow = {}

function scripts.decal_soldier_shadow.update(this, store)
	while true do
		if this.entity.health.dead then
			if not this.entity.health.last_damage_types == 0 then
				U.y_wait(store, fts(this.dissapear_time))
			end

			queue_remove(store, this)

			return
		end

		local offset_y = this.entity.render.sprites[1].offset.y
		local shadow_scale = 1 - this.shadow_shrink * offset_y / this.max_height

		this.render.sprites[1].scale = v(shadow_scale, shadow_scale)

		coroutine.yield()
	end
end

scripts.moon_controller_s72 = {}

function scripts.moon_controller_s72.insert_hook(this, store)
	if this.enemy then
		for _, s in pairs(this.render.sprites) do
			if not s.color then
				s.color = {255, 255, 255}
			end

			if not s.alpha then
				s.alpha = 255
			end

			s.color[1] = s.color[1] * 50 / 255
			s.color[2] = s.color[2] * 200 / 255
			s.alpha = s.alpha * 150 / 255
		end

		SU.armor_inc(this, E:get_template("moon_controller_s72").enemy_armor_buff)
		SU.magic_armor_inc(this, E:get_template("moon_controller_s72").enemy_magic_armor_buff)
		U.speed_inc(this, E:get_template("moon_controller_s72").enemy_speed_buff)

		if this.health.hp then
			this.health.hp = this.health.hp * (1 + E:get_template("moon_controller_s72").enemy_hp_buff * (0.9 + store.wave_group_number / 12))
		end
	end

	if this.soldier then
		for _, s in pairs(this.render.sprites) do
			if not s.color then
				s.color = {255, 255, 255}
			end

			if not s.alpha then
				s.alpha = 255
			end

			s.color[1] = s.color[1] * 50 / 255
			s.color[2] = s.color[2] * 200 / 255
			s.alpha = s.alpha * 150 / 255
		end

		SU.armor_dec(this, E:get_template("moon_controller_s72").enemy_armor_buff)
		SU.magic_armor_dec(this, E:get_template("moon_controller_s72").enemy_magic_armor_buff)
		U.speed_inc(this, E:get_template("moon_controller_s72").enemy_speed_buff)

		if this.health.hp then
			this.health.hp = this.health.hp * (1 - E:get_template("moon_controller_s72").enemy_hp_buff * (0.9 + store.wave_group_number / 12))
		end
	end
end

function scripts.moon_controller_s72.insert_hook_remove(this, store)
	if this.enemy then
		for _, s in pairs(this.render.sprites) do
