function scripts.controller_stage_03_arborean_babies.update(this, store, script)
	local babies = {}
	local count = 1

	for _, v in pairs(store.entities) do
		if v.template_name == "decal_arborean_baby_clickeable" then
			babies[count] = v
			count = count + 1
		end
