	es.pos.x, es.pos.y = target.pos.x + target.unit.hit_offset.x, target.pos.y + target.unit.hit_offset.y
	es.render.sprites[1].ts = store.tick_ts

	queue_insert(store, es)
	queue_remove(store, this)
end

